ons of other notable legislation that this legislation amends; wikilink or external link where possible. --> |repeals = <!-- Citations of other notable legislation that this legislation repeals; wikilink or external link where possible. --> |amended_by = <!-- Citations of other notable legislation that amends this legislation; wikilink or external link where possible. --> |repealed_by = <!-- Citation of the legislation that repealed this legislation; wikilink or external link if possible. --> |related_legislation = <!-- Names and citations of any other related legislation; wikilink name and external link citation where possible. --> |summary = |keywords = |status = <!-- not yet in force/not fully in force/current/in force/amended/expired/spent/repealed/struck down/halted/void/void ab initio --> }} </syntaxhighlight> {{Hidden end}}
===Proposed legislation considered (but failed) or in consideration by a legislature (e.g. a bill)=== {{Hidden begin|title=Click [show] to view}} <syntaxhighlight lang="wikitext" style="overflow:auto"> {{Infobox legislation |short_title = <!-- Name of bill. --> |legislature = <!-- Name of considering legislature, wikilinked. --> |image = |imagesize = |image_upright = |imagealt = |caption = |long_title = |citation = <!-- Citation of bill. --> |territorial_extent = |considered_by = <!-- Use if bill did not pass or hasn't been passed by the chamber (for bicameral legislatures, this is the chamber the bill was first introduced). --> |enacted_by = <!-- Use if bill passed the chamber but was vetoed or have not yet received assent, or, for bicameral legislatures, did not pass or have not yet passed the second chamber. --> |date_enacted = <!-- Pick one of date_enacted or date_passed as appropriate in jurisdiction. Only use if enacted_by is used. --> |date_passed = <!-- Pick one of date_enacted or date_passed as appropriate in jurisdiction. Only use if enacted_by is used. --> |considered_by2 = <!-- For bicameral legislatures only. Use if bill did not pass or hasn't been passed by the second chamber. --> |enacted_by2 = <!-- For bicameral legislatures only. Use if bill passed the second chamber but was vetoed or have not yet received assent. --> |date_enacted2 = <!-- For bicameral legislatures only. Pick one of date_enacted2 or date_passed2 as appropriate in jurisdiction. Only use if enacted_by2 is used. --> |date_passed2 = <!-- For bicameral legislatures only. Pick one of date_enacted2 or date_passed2 as appropriate in jurisdiction. Only use if enacted_by2 is used. --> |date_vetoed = <!-- For jurisdiction where a veto is used. --> |vetoed_by = <!-- Only use if date_vetoed is used. --> |veto_type = <!-- Only use if the jurisdiction allows for several types of veto, e.g. returning a bill to the legislature or referring it to a constitutional court. Pocket vetoes should not be placed here. --> |reference_holding = <!-- For jurisdictions where a constitutional veto (a bill is referred to the supreme or constitutional court) is used. The holding of the court as to the constitutionality of a bill; wikilink or external link to the ruling where possible. --> |date_pocket_vetoed = <!-- For jurisdiction where a pocket veto is used (e.g. if no action is taken on a bill after it is presented to the head of state, it is killed automatically). --> |bill_history_url = |bill = <!-- Name of relevant bill debated in the chamber listed in enacted_by or considered_by. Omit if the legislation is still a bill in this chamber and the bill name used in short_title. --> |bill_citation = |bill_date = |introduced_by = <!-- Name of member introducing the bill in the chamber. --> |committee_responsible = <!-- Name of committee of the chamber responsible for the bill, in short form (e.g. "Ways and Means", not "House Committee on Ways and Means"). --> |preliminary_reading = |preliminary_reading_for = |preliminary_reading_against = |preliminary_reading_abstention = |preliminary_reading_absent = |preliminary_reading_presentnotvoting = |1st_reading = |1st_reading = |1st_reading_for = |1st_reading_against = |1st_reading_abstention = |1st_reading_absent = |1st_reading_presentnotvoting = |committee_post1st = <!-- If consideration by committee occurs between 1st and 2nd readings; pick none or one of committee_post1st or committee_post2nd as appropriate in jurisdiction. --> |2nd_reading = |2nd_reading = |2nd_reading_for = |2nd_reading_against = |2nd_reading_abstention = |2nd_reading_absent = |2nd_reading_presentnotvoting = |committee_post2nd = <!-- If consideration by committee occurs between 2nd and 3rd readings; pick none or one of committee_post1st or committee_post2nd as appropriate in jurisdiction. --> |committee_whole_label = |committee_whole = |3rd_reading = |3rd_reading = |3rd_reading_for = |3rd_reading_against = |3rd_reading_abstention = |3rd_reading_absent = |3rd_r